EXISTS (`CloseableInitExpr CIE`, `RefType T`) {
  AND {
    (`CIE's type is T`),
    EXISTS (`RefType SUP`) {
      AND {
        (`SUP is an ancestor type of T`),
        EXISTS (`Method M`) {
          AND {
            (`M is declared in SUP`),
            (`M's name is "close"`)
          }
        },
        OR {
          (`SUP's qualified name is "java.sql.Connection"`),
          (`SUP's qualified name is "java.sql.Statement"`),
          (`SUP's qualified name is "java.sql.ResultSet"`)
        }
      }
    },
    NOT {
      EXISTS (`CloseableInitExpr INNER`) {
        AND {
          (`INNER is a transitive parent of CIE via closeableInit`),
          OR {
            AND {
              (`INNER is locally initialized`),
              (`INNER is a ClassInstanceExpr`),
              NOT { EXISTS (`Expr ARG`) { (`ARG is an argument of INNER`) } }
            },
            AND {
              (`INNER is locally initialized`),
              EXISTS (`RefType TYPE_INNER`) {
                AND {
                  (`TYPE_INNER is the type of INNER`),
                  EXISTS (`Method CLOSE_METHOD`) {
                    AND {
                      (`CLOSE_METHOD is declared in TYPE_INNER`),
                      (`CLOSE_METHOD's name is "close"`),
                      NOT { EXISTS (`Stmt S`) { (`S is a child statement in CLOSE_METHOD's body`) } }
                    }
                  }
                }
              }
            },
            EXISTS (`CloseableInitExpr SQLSTMT`, `LocalVariableDecl V`) {
              AND {
                (`SQLSTMT's type's ancestor is a TypeStatement`),
                (`SQLSTMT flows into V`),
                (`CIE's type is TypeResultSet`),
                (`CIE is a SqlResourceOpeningMethodCall`),
                (`CIE's qualifier is an access of V`)
              }
            },
            EXISTS (`MethodCall MA`) {
              AND {
                (`CIE is a ClassInstanceExpr`),
                (`MA is an argument of CIE`),
                OR {
                  (`MA's method is ServletResponseGetOutputStreamMethod`),
                  (`MA's method is ServletResponseGetWriterMethod`),
                  (`MA's method is ServletRequestGetBodyMethod`)
                }
              }
            },
            EXISTS (`CloseableInitExpr INNER2`) {
              AND {
                (`INNER2 is a transitive parent of CIE via closeableInit`)
              }
            },
            EXISTS (`CloseableInitExpr INNER3`) {
              AND {
                (`INNER3 is a transitive parent of CIE via closeableInit`),
                EXISTS (`LocalVariableDecl VAR`) {
                  AND {
                    (`INNER3's closeable variable is VAR`)
                  }
                }
              }
            }
          }
        }
      }
    },
    OR {
      AND {
        (`CIE is locally initialized`),
        NOT { EXISTS (`Variable VAR`) { (`CIE flows into VAR`) } },
        NOT {
          EXISTS (`ClassInstanceExpr OUTER`) {
            AND {
              (`OUTER is locally initialized`),
              (`CIE is an argument of OUTER`)
            }
          }
        }
      },
      AND {
        (`CIE is locally initialized`)
      }
    },
    NOT {
      EXISTS (`CloseableInitExpr CIE2`) {
        AND {
          (`CIE2 is a transitive parent of CIE via closeableInit`),
          (`CIE2 is not CIE`),
          OR {
            AND {
              (`CIE2 is locally initialized`),
              NOT { EXISTS (`Variable VAR`) { (`CIE2 flows into VAR`) } },
              NOT {
                EXISTS (`ClassInstanceExpr OUTER`) {
                  AND {
                    (`OUTER is locally initialized`),
                    (`CIE2 is an argument of OUTER`)
                  }
                }
              }
            },
            AND {
              (`CIE2 is locally initialized`)
            }
          }
        }
      }
    }
  }
}
